INSERT INTO blog_posts (slug, title, content, meta_description, tags, published_at) VALUES
('2026-youth-welfare-guide', '2026년 청년 복지 총정리: 놓치면 후회할 혜택 모음', '# 2026년 청년이 받을 수 있는 복지 혜택\n\n올해도 다양한 청년 복지 정책이 시행됩니다.', '2026년 청년이 받을 수 있는 복지 혜택을 총정리했습니다.', ARRAY['청년', '복지', '2026'], '2026-03-01'),
('small-business-loan-2026', '소상공인 대출 비교: 2026년 정책자금 금리·한도 총정리', '# 2026년 소상공인 정책자금 가이드\n\n소상공인이 받을 수 있는 정부 대출을 비교했습니다.', '2026년 소상공인 정책자금을 금리, 한도별로 비교합니다.', ARRAY['소상공인', '대출', '2026'], '2026-03-15');
